mapper.select:
/* SQL ID : MsgRcptnAgreDAO.selectRcptnAgreYrList 설 명 : 알림수신동의 학사년도 목록 조회 */ SELECT DISTINCT S.SBJCT_YR FROM TB_LMS_SBJCT S WHERE S.DELYN = 'N'
AND S.PROF_ID = #{profId}
ORDER BY S.SBJCT_YR DESC

/*
     SQL ID : MsgRcptnAgreDAO.selectRcptnAgreSmstrList
     설  명 : 알림수신동의 학기 목록 조회
 */
SELECT DISTINCT TRIM(S.SBJCT_SMSTR) AS SBJCT_SMSTR
FROM TB_LMS_SBJCT S
WHERE S.DELYN = 'N'

  AND S.PROF_ID = #{profId}


  AND S.SBJCT_YR = #{sbjctYr}

ORDER BY TRIM(S.SBJCT_SMSTR) ASC

/* SQL ID : MsgRcptnAgreDAO.selectRcptnAgreDeptList 설 명 : 알림수신동의 학과 목록 조회 */ SELECT DISTINCT D.DEPT_ID , D.DEPTNM FROM TB_LMS_SBJCT S INNER JOIN TB_LMS_DEPT D ON S.DEPT_ID = D.DEPT_ID WHERE S.DELYN = 'N'
AND S.PROF_ID = #{profId}
ORDER BY D.DEPTNM ASC

/*
     SQL ID : MsgRcptnAgreDAO.selectRcptnAgreSbjctList
     설  명 : 알림수신동의 운영과목 목록 조회
 */
SELECT S.SBJCT_ID
     , S.SBJCTNM
FROM TB_LMS_SBJCT S
WHERE S.DELYN = 'N'

  AND S.PROF_ID = #{profId}


  AND S.SBJCT_YR = #{sbjctYr}


  AND TRIM(S.SBJCT_SMSTR) = TRIM(#{sbjctSmstr})


  AND S.DEPT_ID = #{deptId}

ORDER BY S.SBJCTNM ASC
